function getCompanyAge() {
  const founded = new Date("2018-11-08");
  const now = new Date();
  const diffMs = now - founded;
  const years = diffMs / (1000 * 60 * 60 * 24 * 365.25);
  return Math.floor(years * 10) / 10; // СИђСйЇт░ЈТЋИ
}

