function getAutoProgress(p) {
  // СЙЮтиЦТюЪтцЕТЋИУЄфтІЋУеѕу«Ќжђ▓т║д№╝ѕти▓жЂјтцЕТЋИ / уИйтцЕТЋИ№╝Ѕ
  if (!p.constructionStartDate || !p.constructionEndDate) return p.progress || 0;
  try {
    const start = new Date(p.constructionStartDate);
    const end = new Date(p.constructionEndDate);
    const today = new Date();
    if (isNaN(start.getTime()) || isNaN(end.getTime())) return p.progress || 0;
    const total = Math.max(1, (end - start) / 86400000);
    const elapsed = Math.max(0, Math.min(total, (today - start) / 86400000));
    return Math.round((elapsed / total) * 100);
  } catch { return p.progress || 0; }
}

function getJunkyardWarning(count) {
  if (count >= 5) return JUNKYARD_WARNINGS[Math.floor(count % JUNKYARD_WARNINGS.length)];
  return null;
}

// РћђРћђ тюеУЂиУ│ЄТГиУеѕу«Ќ РћђРћђ
function calcTenure(startDate) {
  if (!startDate) return null;
  const start = new Date(startDate);
  const now = new Date();
  const diffMs = now - start;
  if (diffMs < 0) return null;
  const days = Math.floor(diffMs / (1000 * 60 * 60 * 24));
  const months = Math.floor(days / 30.44);
  const years = Math.floor(months / 12);
  const remMonths = months % 12;
  const remDays = days - Math.floor(months * 30.44);
  return { days, months, years, remMonths, remDays: Math.max(0, remDays) };
}

function getTenureLevel(days) {
  if (days < 90) return "УЈюж│Ц";
  if (days < 180) return "т»ду┐њ";
  if (days < 365) return "ТѕљжЋи";
  if (days < 730) return "уєЪуи┤";
  if (days < 1095) return "У│ЄТи▒";
  return "тѓ│Уфф";
}

function getTenureColor(days) {
  if (days < 90) return { color: "#7eb8f7", bg: "rgba(126,184,247,0.12)", border: "rgba(126,184,247,0.3)" };
  if (days < 180) return { color: "#70d4c0", bg: "rgba(112,212,192,0.12)", border: "rgba(112,212,192,0.3)" };
  if (days < 365) return { color: "#80e890", bg: "rgba(128,232,144,0.12)", border: "rgba(128,232,144,0.3)" };
  if (days < 730) return { color: "#f0d060", bg: "rgba(240,208,96,0.12)", border: "rgba(240,208,96,0.3)" };
  if (days < 1095) return { color: "#f0a050", bg: "rgba(240,160,80,0.12)", border: "rgba(240,160,80,0.3)" };
  return { color: "#e87070", bg: "rgba(232,112,112,0.12)", border: "rgba(232,112,112,0.3)", gradient: true };
}

