function getDailyFortune(projects, currentUser) {
  const today = new Date();
  const seed = today.getFullYear() * 10000 + (today.getMonth() + 1) * 100 + today.getDate() + (currentUser?.email?.length || 0);

  // жЂІтІбуГЅу┤џ
  const fortuneIdx = seed % FORTUNE_LEVELS.length;
  const fortune = FORTUNE_LEVELS[fortuneIdx];
  const descIdx = (seed * 3) % fortune.desc.length;

  // ТАѕС╗ХтБЊтіЏтѕєТъљ
  const pressureProjects = [];
  projects.forEach(p => {
    if (p.stage === "ТЈљТАѕСИГ" && p.consultDate) {
      const result = getRemainingWorkDays(p.consultDate, 15);
      if (result && !p.proposalDate && result.remaining <= 5) {
        pressureProjects.push({ name: p.name, reason: `ТЈљТАѕтЅЕ ${result.remaining} тцЕ` });
      }
    }
    if (p.stage === "ти▓у░йу┤ё") {
      const lastMeeting = (p.signedMeetingDates || []).filter(m => m.start).slice(-1)[0];
      if (lastMeeting) {
        const result = getRemainingWorkDays(lastMeeting.start, 10);
        if (result && result.remaining <= 4) {
          pressureProjects.push({ name: p.name, reason: `С║цС╗ХтЅЕ ${result.remaining} тцЕ` });
        }
      }
    }
    if (p.stage === "ТќйтиЦСИГ" && p.progress === 0 && p.startDate) {
      pressureProjects.push({ name: p.name, reason: "ТќйтиЦжђ▓т║д 0%№╝їжюђУдЂТЏ┤Тќ░" });
    }
  });

  const pressureLevel = pressureProjects.length === 0 ? "Сйј" : pressureProjects.length <= 2 ? "СИГ" : "жФў";
  const pressureColor = pressureProjects.length === 0 ? "#50c878" : pressureProjects.length <= 2 ? "#f0a850" : "#e05b5b";

  // У▓АжЂІ
  const totalPending = projects.filter(p => p.stage === "ТќйтиЦСИГ" || p.stage === "ти▓у░йу┤ё")
    .reduce((s, p) => s + (parseFloat(p.budget) || 0), 0);

  // С╗іТЌЦт╗║УГ░
  const advices = [
    "тЁѕУЎЋуљєТюђуЄЎТЅІуџёТАѕтГљ№╝їтЁХС╗ќуџёС║цухдт«Єт«Ўсђѓ",
    "С╗ітцЕжЂЕтљѕТЅЊт╣ЙжђџжЏ╗УЕ▒ухдС╣ЁТюфУЂ»у╣Фуџёт╗атЋєсђѓ",
    "ТііжѓБтђІСИђуЏ┤ТІќУЉЌуџётюќжЮб№╝їС╗ітцЕт░▒т«їТѕљт«Ѓсђѓ",
    "УиЪт«бТѕХуб║УфЇСИђтђІт░Ју┤░у»ђ№╝їтЈ»С╗ЦжЂ┐тЁЇтцДж║╗уЁЕсђѓ",
    "ТЋ┤уљєСИђСИІта▒тЃ╣тќ«№╝їТЋИтГЌТИЁТЦџт┐ЃТЃЁтЦйсђѓ",
    "С╝ЉТЂ»СИђСИІтєЇу╣╝у║ї№╝їжЮѕТёЪтюетњќтЋАУБАсђѓ",
    "С╗ітцЕСИЇУдЂТћ╣УХЁжЂјСИЅТгА№╝їуггтЏЏТгАжђџтИИТЏ┤ти«сђѓ",
    "тЁѕТііу░Атќ«уџёС║ІтЂџт«ї№╝їУцЄжЏюуџёТюЃУ«іт«╣ТўЊсђѓ",
  ];
  const adviceIdx = (seed * 7) % advices.length;

  // уИйУЕЋтЃ╣
  const ratings = pressureProjects.length === 0 && fortune.level === "тцДтљЅ"
    ? { text: "С╗іТЌЦТ╗┐тѕєУеГУеѕтИФ№╝ЂТЅђТюЅТАѕС╗Хжђ▓т║дУХЁтЅЇ№╝їу╣╝у║їУАЮ№╝Ђ", emoji: "­ЪћЦ", color: "#f0d050" }
    : pressureProjects.length >= 3
    ? { text: "С╗іТЌЦтБЊтіЏт▒▒тцД№╝їСйєСйаТњљжЂјСЙєС║є№╝їТўјтцЕТюЃТЏ┤тЦй№╝Ђ", emoji: "­Ъњф", color: "#5b8af0" }
    : pressureProjects.length >= 1
    ? { text: `С╗іТЌЦСИГуГЅуЎ╝ТЈ«№╝їТюЅ ${pressureProjects.length} С╗ХТАѕтГљжюђУдЂжЌюТ│е№╝їтіаТіітІЂ№╝Ђ`, emoji: "РџА", color: "#f0a850" }
    : { text: "С╗іТЌЦт╣│уЕЕжаєТџб№╝їу╣╝у║їС┐ЮТїЂтЦйу»ђтЦЈ№╝Ђ", emoji: "Рюе", color: "#50c878" };

  return { fortune, descIdx, pressureProjects, pressureLevel, pressureColor, totalPending, advice: advices[adviceIdx], rating: ratings };
}

