function getCompanyTitle(totalProjects) {
  const today = new Date();
  const seed = today.getDate() + today.getMonth();
  let level = COMPANY_TITLES[0];
  for (const t of COMPANY_TITLES) {
    if (totalProjects >= t.min) level = t;
  }
  return level.titles[seed % level.titles.length];
}

