  // тЁгтЉіУиЉждгуЄѕти▓У«ђуІђТЁІ
  const [annMarqueeRead, setAnnMarqueeRead] = useState(() => {
    try { return localStorage.getItem("mudao_ann_read_id") || ""; } catch { return ""; }
  });
  const [expandedAnn, setExpandedAnn] = useState(null);
  const [collapsedTrashYears, setCollapsedTrashYears] = useState({});
  const [deletedTestIds, setDeletedTestIds] = useState(() => {
    try { return JSON.parse(localStorage.getItem("mudao_deleted_test_ids") || "[]"); } catch { return []; }
  }); // т▒ЋжќІуџётЁгтЉі id
  const [importText, setImportText] = useState("");
  const [allUsers, setAllUsers] = useState([]);

  const [projects, setProjects] = useState(() => {
    try { const s = localStorage.getItem("mudao_projects"); return s ? JSON.parse(s) : SAMPLE; } catch { return SAMPLE; }
  });
  const [memos, setMemos] = useState(() => {
    try { const s = localStorage.getItem("mudao_memos"); return s ? JSON.parse(s) : SAMPLE_MEMOS; } catch { return SAMPLE_MEMOS; }
  });
  const [materials, setMaterials] = useState(() => {
    try { const s = localStorage.getItem("mudao_materials"); return s ? JSON.parse(s) : SAMPLE_MATERIALS; } catch { return SAMPLE_MATERIALS; }
  });
  const [matModal, setMatModal] = useState(null);
  const [matForm, setMatForm] = useState(EMPTY_MATERIAL);
  const [matCatFilter, setMatCatFilter] = useState("тЁежЃе");
  const [matSearch, setMatSearch] = useState("");
  const [userName, setUserName] = useState(() => {
    try { return localStorage.getItem("mudao_username") || ""; } catch { return ""; }
  });
  const [editingName, setEditingName] = useState(false);
  const [trashProjects, setTrashProjects] = useState(() => {
    try { const s = localStorage.getItem("mudao_trash"); return s ? JSON.parse(s) : []; } catch { return []; }
  });

  // УЄфтІЋтё▓тГўтѕ░ LocalStorage
  useEffect(() => { try { localStorage.setItem("mudao_projects", JSON.stringify(projects)); } catch {} }, [projects]);
  useEffect(() => { try { localStorage.setItem("mudao_memos", JSON.stringify(memos)); } catch {} }, [memos]);
  useEffect(() => { try { localStorage.setItem("mudao_materials", JSON.stringify(materials)); } catch {} }, [materials]);
