  useEffect(() => { try { localStorage.setItem("mudao_trash", JSON.stringify(trashProjects)); } catch {} }, [trashProjects]);

  // тЁгтЉіуЏИжЌю state№╝ѕт┐Ёжаѕтюе useEffect тЅЇжЮб№╝Ѕ
  const [announcements, setAnnouncements] = useState([]);
