  const [adminInput, setAdminInput] = useState("");
  const [showAdminLogin, setShowAdminLogin] = useState(false);

  // У╝ЅтЁЦтЁгтЉі
  useEffect(() => {
    async function loadAnn() {
      try {
        const data = await sbFetch("announcements?select=*&order=pinned.desc,id.desc");
        if (Array.isArray(data)) setAnnouncements(data);
      } catch (e) { console.error("тЁгтЉіУ╝ЅтЁЦтц▒ТЋЌ:", e); }
      setAnnLoading(false);
    }
    loadAnn();
  }, []);

  // тЁгтЉіТЊЇСйю
  async function saveAnnouncement() {
    if (!annForm.title.trim()) return;
    try {
      const body = {
        title: annForm.title.trim(),
        content: annForm.content || "",
        date: annForm.date || new Date().toISOString().split("T")[0],
        pinned: annForm.pinned === true || annForm.pinned === "true",
        category: annForm.category || "general",
      };
      if (annForm.id) {
        await sbFetch(`announcements?id=eq.${annForm.id}`, {
          method: "PATCH",
          headers: { "Prefer": "return=representation" },
          body: JSON.stringify(body),
        });
      } else {
        await sbFetch("announcements", {
          method: "POST",
          headers: { "Prefer": "return=representation" },
          body: JSON.stringify(body),
        });
      }
      const refreshed = await sbFetch("announcements?select=*&order=pinned.desc,id.desc");
      if (Array.isArray(refreshed)) setAnnouncements(refreshed);
    } catch (e) {
      console.error("тЁгтЉітё▓тГўтц▒ТЋЌ:", e);
      alert("тё▓тГўтц▒ТЋЌ№╝їУФІжЄЇУЕд");
    }
    setAnnModal(null);
  }

  async function deleteAnnouncement(id) {
    try {
      await sbFetch(`announcements?id=eq.${id}`, { method: "DELETE" });
      setAnnouncements(announcements.filter(a => a.id !== id));
    } catch (e) { console.error(e); }
    setAnnModal(null);
  }

  function loginAdmin() {
    if (adminInput === ADMIN_PASSWORD) {
      setIsAdmin(true);
      try { localStorage.setItem("mudao_admin", "1"); } catch {}
      setShowAdminLogin(false);
      setAdminInput("");
    } else {
      alert("т»єуб╝жї»Уфц");
    }
  }
  const [tab, setTab] = useState("home");
  const [search, setSearch] = useState("");

  // modal state
  const [modal, setModal] = useState(null); // null | "detail" | "new" | "edit" | "memo_new" | "memo_edit"
  const [activeProject, setActiveProject] = useState(null);
  const [activeMemo, setActiveMemo] = useState(null);

  // detail section
  const [detailSection, setDetailSection] = useState("info");

  // form state
  const [form, setForm] = useState(EMPTY_PROJECT);
  const [formTab, setFormTab] = useState("basic");

  // memo form
  const [memoForm, setMemoForm] = useState(EMPTY_MEMO);

  // payment form (inside detail)
  const [payAmt, setPayAmt] = useState("");
  const [payDate, setPayDate] = useState(new Date().toISOString().split("T")[0]);
  const [payNote, setPayNote] = useState("");

  // РћђРћђ helpers РћђРћђ
  // тљѕСйхжќІуЎ╝УђЁТИгУЕдУ│ЄТќЎ
  const allVisibleProjects = (() => {
    const isDevEmail = currentUser?.email === DEVELOPER_EMAIL;
    const base = isDevEmail
      ? [...projects, ...DEVELOPER_TEST_PROJECTS.filter(tp => !projects.find(p => p.id === tp.id))]
      : projects;
    return base.filter(p => canSeeProject(currentUser, p, devMode));
  })();

  const allVisibleTrash = (() => {
    const base = currentUser?.email === DEVELOPER_EMAIL
      ? [...trashProjects, ...DEVELOPER_TRASH_EXAMPLES.filter(te => !trashProjects.find(t => t.id === te.id))]
      : trashProjects;
    return base.filter(t => !deletedTestIds.includes(t.id));
  })();

  const stageProjects = (stage) => allVisibleProjects.filter(p => p.stage === stage);

  function openDetail(p) {
    setActiveProject(p);
    setDetailSection("info");
    setModal("detail");
  }

  function openNew(stage = "ТЈљТАѕСИГ") {
    setForm({ ...EMPTY_PROJECT, id: null, stage, quote: DEFAULT_QUOTE(), changeOrders: DEFAULT_BILLING(), extraItems: [], absorbedCosts: [], billing: DEFAULT_BILLING(), defects: [], payments: [], meetingDates: [], signedMeetingDates: [], clientRequirements: [], designFeePayments: EMPTY_PROJECT.designFeePayments });
    setFormTab("basic");
    setModal("new");
  }

  function openEdit(p) {
    setForm({
      ...p,
      quote: p.quote || DEFAULT_QUOTE(),
      changeOrders: p.changeOrders || DEFAULT_BILLING(),
      extraItems: p.extraItems || [],
      absorbedCosts: p.absorbedCosts || [],
      billing: p.billing || DEFAULT_BILLING(),
      defects: p.defects || [],
      payments: p.payments || [],
      meetingDates: p.meetingDates || [],
      signedMeetingDates: p.signedMeetingDates || [],
      clientRequirements: p.clientRequirements || [],
      designFeePayments: p.designFeePayments || EMPTY_PROJECT.designFeePayments,
      assistantMemos: p.assistantMemos || [],
      foremanWorkItems: p.foremanWorkItems || [],
    });
    setFormTab("basic");
    setModal("edit");
  }

  const [cloudSyncing, setCloudSyncing] = useState(false);
  const [cloudMsg, setCloudMsg] = useState("");
  const [hasCloudUpdate, setHasCloudUpdate] = useState(false);
  const [lastSyncTime, setLastSyncTime] = useState(Date.now());

  // т«џТюЪТфбТЪЦжЏ▓уФ»Тў»тљдТюЅТЏ┤Тќ░№╝ѕТ»Ј60уДњ№╝Ѕ
  useEffect(() => {
    if (!currentUser) return;
    const interval = setInterval(async () => {
      try {
        const data = await sbFetch("projects?select=updated_at&order=updated_at.desc&limit=1");
        if (Array.isArray(data) && data.length > 0) {
          const latestUpdate = new Date(data[0].updated_at).getTime();
          if (latestUpdate > lastSyncTime) setHasCloudUpdate(true);
        }
      } catch {}
    }, 60000);
    return () => clearInterval(interval);
  }, [currentUser, lastSyncTime]);

  async function syncFromCloud() {
    setCloudSyncing(true);
    try {
      const cloudProjects = await cloudLoadProjects(currentUser, allUsers);
      if (cloudProjects.length > 0) {
        setProjects(prev => {
          const cloudIds = new Set(cloudProjects.map(p => p.id));
          const localOnly = prev.filter(p => !cloudIds.has(p.id));
          return [...cloudProjects, ...localOnly];
        });
      }
      setLastSyncTime(Date.now());
      setHasCloudUpdate(false);
      setCloudMsg("РюЁ ти▓тљїТГЦТюђТќ░У│ЄТќЎ");
      setTimeout(() => setCloudMsg(""), 3000);
    } catch { setCloudMsg("Рџа№ИЈ тљїТГЦтц▒ТЋЌ"); setTimeout(() => setCloudMsg(""), 3000); }
    setCloudSyncing(false);
  }

  async function saveProject() {
    if (!form.name.trim()) return;
    const projectToSave = form.id ? { ...form } : { ...form, id: Date.now(), ownerEmail: currentUser.email };
    if (form.id) {
      setProjects(projects.map(p => p.id === form.id ? projectToSave : p));
    } else {
      setProjects(prev => [projectToSave, ...prev]);
    }
    setModal(null);
    // жЏ▓уФ»тљїТГЦ
    setCloudSyncing(true);
    const ok = await cloudSaveProject(projectToSave, currentUser.email);
    setCloudMsg(ok ? "РюЁ ти▓тљїТГЦтѕ░жЏ▓уФ»" : "Рџа№ИЈ жЏ▓уФ»тљїТГЦтц▒ТЋЌ");
    setTimeout(() => setCloudMsg(""), 3000);
    setCloudSyncing(false);
  }

  async function deleteProject(id) {
    setProjects(projects.filter(p => p.id !== id));
    setModal(null);
    await cloudDeleteProject(id, currentUser.email);
  }

  async function advanceStage(id) {
    const updatedProjects = projects.map(p => {
      if (p.id !== id) return p;
      const idx = STAGES.indexOf(p.stage);
      if (idx >= STAGES.length - 1) return p;
      const next = STAGES[idx + 1];
      // т«їтиЦТЎѓСИЇУЄфтІЋУеГт«џТЌЦТюЪ№╝їУ«ЊућеТѕХТЅІтІЋтАФ
      return { ...p, stage: next };
    });
    setProjects(updatedProjects);
    setModal(null);
    const updated = updatedProjects.find(p => p.id === id);
    if (updated) await cloudSaveProject(updated, currentUser.email);
  }

  function toggleDefect(projectId, defectId) {
    setProjects(prev => prev.map(p => {
      if (p.id !== projectId) return p;
      return { ...p, defects: p.defects.map(d => d.id === defectId ? { ...d, done: !d.done } : d) };
    }));
    // update activeProject ref
    setActiveProject(prev => {
      if (!prev || prev.id !== projectId) return prev;
      return { ...prev, defects: prev.defects.map(d => d.id === defectId ? { ...d, done: !d.done } : d) };
    });
  }

  function addPayment() {
    if (!payAmt || !activeProject) return;
    const newPayment = { id: Date.now(), amount: payAmt, date: payDate, note: payNote };
    setProjects(prev => prev.map(p => {
      if (p.id !== activeProject.id) return p;
      const payments = [...(p.payments || []), newPayment];
      const { totalPrice } = calcProfit(p);
      const totalPaid = payments.reduce((s, v) => s + num(v.amount), 0);
      const progress = totalPrice > 0 ? Math.min(100, Math.round((totalPaid / totalPrice) * 100)) : p.progress;
      const closedDate = progress >= 100 ? (p.closedDate || new Date().toISOString().split("T")[0]) : p.closedDate;
      return { ...p, payments, progress, closedDate };
    }));
    setActiveProject(prev => {
      if (!prev) return prev;
      const payments = [...(prev.payments || []), newPayment];
      const { totalPrice } = calcProfit(prev);
      const totalPaid = payments.reduce((s, v) => s + num(v.amount), 0);
      const progress = totalPrice > 0 ? Math.min(100, Math.round((totalPaid / totalPrice) * 100)) : prev.progress;
      const closedDate = progress >= 100 ? (prev.closedDate || new Date().toISOString().split("T")[0]) : prev.closedDate;
      return { ...prev, payments, progress, closedDate };
    });
    setPayAmt(""); setPayNote("");
  }

  const f = (k) => (e) => setForm(prev => ({ ...prev, [k]: e.target.value }));
  const mf = (k) => (e) => setMemoForm(prev => ({ ...prev, [k]: e.target.value }));

  function setQuote(item, field, val) {
    setForm(prev => ({ ...prev, quote: { ...prev.quote, [item]: { ...prev.quote[item], [field]: val } } }));
  }
  function setBilling(item, val) {
    setForm(prev => ({ ...prev, billing: { ...prev.billing, [item]: val } }));
  }
  function setChangeOrder(item, val) {
    setForm(prev => ({ ...prev, changeOrders: { ...prev.changeOrders, [item]: val } }));
  }
  function addExtraItem() {
    const newItem = { id: Date.now(), name: "", price: "", cost: "", collected: false };
    setForm(prev => ({ ...prev, extraItems: [...(prev.extraItems || []), newItem] }));
  }
  function updateExtraItem(id, field, val) {
    setForm(prev => ({ ...prev, extraItems: prev.extraItems.map(e => e.id === id ? { ...e, [field]: val } : e) }));
  }
  function removeExtraItem(id) {
    setForm(prev => ({ ...prev, extraItems: prev.extraItems.filter(e => e.id !== id) }));
  }
  function addAbsorbedCost() {
    setForm(prev => ({ ...prev, absorbedCosts: [...(prev.absorbedCosts || []), { id: Date.now(), name: "", amount: "" }] }));
  }
  function updateAbsorbedCost(id, field, val) {
    setForm(prev => ({ ...prev, absorbedCosts: prev.absorbedCosts.map(a => a.id === id ? { ...a, [field]: val } : a) }));
  }
  function removeAbsorbedCost(id) {
    setForm(prev => ({ ...prev, absorbedCosts: prev.absorbedCosts.filter(a => a.id !== id) }));
  }

  // material helpers
  function openNewMat() { setMatForm({ ...EMPTY_MATERIAL }); setMatModal("new"); }
  function openEditMat(m) { setMatForm({ ...m }); setMatModal("edit"); }
  function saveMat() {
    if (!matForm.name.trim()) return;
    if (matForm.id) setMaterials(materials.map(m => m.id === matForm.id ? { ...matForm } : m));
    else setMaterials([{ ...matForm, id: Date.now() }, ...materials]);
    setMatModal(null);
  }
  function deleteMat(id) { setMaterials(materials.filter(m => m.id !== id)); setMatModal(null); }
  const maf = (k) => (e) => setMatForm(prev => ({ ...prev, [k]: e.target.value }));

  const filteredMaterials = materials.filter(m =>
    (matCatFilter === "тЁежЃе" || m.category === matCatFilter) &&
    (matSearch === "" || m.name.includes(matSearch) || m.brand.includes(matSearch) || m.model.includes(matSearch))
  );

  // тъЃтюЙта┤ТЊЇСйю
  async function moveToTrash(project) {
    const year = new Date().getFullYear();
    const trashItem = { ...project, trashedAt: new Date().toISOString(), trashedYear: year };
    setTrashProjects(prev => [trashItem, ...prev]);
    setProjects(projects.filter(p => p.id !== project.id));
    setModal(null);
    await cloudDeleteProject(project.id, currentUser.email);
  }

  async function reviveFromTrash(trashItem) {
    const { trashedAt, trashedYear, ...project } = trashItem;
    const revived = { ...project, id: Date.now() };
    setProjects(prev => [revived, ...prev]);
    setTrashProjects(prev => prev.filter(t => t.id !== trashItem.id));
    await cloudSaveProject(revived, currentUser.email);
  }

  function deleteFromTrash(id) {
    // тЁѕтЙъуюЪт»дтъЃтюЙта┤тѕф
    setTrashProjects(prev => prev.filter(t => t.id !== id));
    // тдѓТъюТў»ТИгУЕдТАѕС╗Х№╝їтіатЁЦти▓тѕфжЎцТИЁтќ«
    const isTestItem = DEVELOPER_TRASH_EXAMPLES.some(t => t.id === id);
    if (isTestItem) {
      setDeletedTestIds(prev => {
        const next = [...prev, id];
        try { localStorage.setItem("mudao_deleted_test_ids", JSON.stringify(next)); } catch {}
        return next;
      });
    }
  }

  // РћђРћђ У╝ЅтЁЦТЅђТюЅТѕљтЊА + жЏ▓уФ»ТАѕС╗Х РћђРћђ
  useEffect(() => {
    if (!currentUser) return;
    async function loadUsersAndProjects() {
      try {
        // У╝ЅтЁЦТѕљтЊА
        const users = await sbFetch("users?select=*&order=created_at.asc");
        if (Array.isArray(users)) setAllUsers(users);
        // У╝ЅтЁЦжЏ▓уФ»ТАѕС╗Х
        const cloudProjects = await cloudLoadProjects(currentUser, users || []);
        if (cloudProjects.length > 0) {
          // тљѕСйх№╝џжЏ▓уФ»ТюЅуџётёфтЁѕ№╝їТюгтю░ТюЅСйєжЏ▓уФ»Т▓њТюЅуџёС╣ЪС┐ЮуЋЎ
          setProjects(prev => {
            const cloudIds = new Set(cloudProjects.map(p => p.id));
            const localOnly = prev.filter(p => !cloudIds.has(p.id));
            return [...cloudProjects, ...localOnly];
          });
        }
      } catch (e) { console.error("У╝ЅтЁЦтц▒ТЋЌ:", e); }
    }
    loadUsersAndProjects();
  }, [currentUser]);

  // РћђРћђ уЎ╗тЁЦ РћђРћђ
  async function handleLogin() {
    setAuthError("");
    setAuthLoading(true);
    try {
      const hash = await hashPassword(authPassword);
      const data = await sbFetch(`users?email=eq.${encodeURIComponent(authEmail)}&password_hash=eq.${hash}&select=*`);
      if (!Array.isArray(data) || data.length === 0) {
        setAuthError("Email Тѕќт»єуб╝жї»Уфц");
      } else {
        const user = data[0];
        setCurrentUser(user);
        localStorage.setItem("mudao_user", JSON.stringify(user));
        if (rememberMe) {
          localStorage.setItem("mudao_saved_email", authEmail);
        } else {
          localStorage.removeItem("mudao_saved_email");
        }
      }
    } catch { setAuthError("уЎ╗тЁЦтц▒ТЋЌ№╝їУФІуеЇтЙїтєЇУЕд"); }
    setAuthLoading(false);
  }

  // РћђРћђ Уе╗тєі РћђРћђ
  async function handleRegister() {
    setAuthError("");
    if (!authEmail || !authPassword || !authName) { setAuthError("УФІтАФт»ФТЅђТюЅТгёСйЇ"); return; }
    if (authPassword.length < 4) { setAuthError("т»єуб╝УЄ│т░Љ 4 тђІтГЌтЁЃ"); return; }
    setAuthLoading(true);
    try {
      const hash = await hashPassword(authPassword);
      const existing = await sbFetch("users?select=id");
      const isFirst = !Array.isArray(existing) || existing.length === 0;
      const role = (authEmail === DEVELOPER_EMAIL || isFirst) ? "design_manager" : "assistant";
      const result = await sbFetch("users", {
        method: "POST",
        body: JSON.stringify({ email: authEmail, name: authName, role, password_hash: hash }),
      });
      if (Array.isArray(result) && result.length > 0) {
        setCurrentUser(result[0]);
        localStorage.setItem("mudao_user", JSON.stringify(result[0]));
      } else { setAuthError("Уе╗тєітц▒ТЋЌ№╝їEmail тЈ»УЃйти▓УбФСй┐уће"); }
    } catch { setAuthError("Уе╗тєітц▒ТЋЌ№╝їУФІуеЇтЙїтєЇУЕд"); }
    setAuthLoading(false);
  }

  function handleLogout() {
    setCurrentUser(null);
    localStorage.removeItem("mudao_user");
  }

  // РћђРћђ тї»тЄ║У│ЄТќЎ РћђРћђ
  function exportData() {
    const data = { projects, trashProjects, memos, materials, userName, exportedAt: new Date().toISOString() };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url; a.download = `mudao-backup-${new Date().toISOString().split("T")[0]}.json`;
    a.click(); URL.revokeObjectURL(url);
  }

  // РћђРћђ тї»тЁЦУ│ЄТќЎ РћђРћђ
  async function importData() {
    try {
      const data = JSON.parse(importText);
      if (data.projects) {
        setProjects(data.projects);
        // тљїТГЦтѕ░жЏ▓уФ»
        setCloudSyncing(true);
        for (const p of data.projects) {
          await cloudSaveProject({ ...p, ownerEmail: p.ownerEmail || currentUser.email }, currentUser.email);
        }
        setCloudSyncing(false);
        setCloudMsg("РюЁ У│ЄТќЎти▓тї»тЁЦСИдтљїТГЦтѕ░жЏ▓уФ»");
        setTimeout(() => setCloudMsg(""), 4000);
      }
      if (data.trashProjects) setTrashProjects(data.trashProjects);
      if (data.memos) setMemos(data.memos);
      if (data.materials) setMaterials(data.materials);
      if (data.userName) setUserName(data.userName);
      setShowExportImport(false);
      setImportText("");
    } catch { alert("РЮї Та╝т╝Јжї»Уфц№╝їУФІуб║УфЇТў»ТГБуб║уџётѓЎС╗йТфћТАѕ"); }
  }

